#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e10+5;
char a[maxn];
int n,k,ans=1,d;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>k;
	for(int i=0; i<n; i++) {
		cin>>a;
		ans=d=1;
		for(int j=0; j<strlen(a); j++) {
			if(ans*(a[j]-'0')>k) {
				cout<<"dame";
				d=0;
				break;
			}
			ans*=(a[j]-'0');
		}
		if(d) {
			cout<<"kawaii";
		}
		cout<<"\n";
	}
	return 0;
}
